SET ANSI_NULLS ON; GO; SET QUOTED_IDENTIFIER ON; GO; SET NOCOUNT ON; SET XACT_ABORT ON;
/*
  Tabsan EduSphere — University Demo Data (8 Semesters, GPA Grading)
  ==================================================================
  1 Tenant x 1 Campus x 4 Depts x 20 Courses x 28 Students
  Grading: GPA (4.0 scale)
*/
IF DB_ID(N'Tabsan-EduSphere') IS NULL BEGIN RAISERROR('Run 01-Schema-Current.sql first.',16,1); RETURN; END;
GO
USE [Tabsan-EduSphere]; GO
DECLARE @Now DATETIME2=SYSUTCDATETIME(),@SAPwdHash NVARCHAR(512)=N'argon2id:kot3aIW+GTcmK4Ji/jGD7BxrNOEh57PLaFMUZrZa5oM=:v+XYusZ0Eu9Xs8Sz/7Hi58z4SrS9KsJ/ynnr/iCkkSk=',@PwdHash NVARCHAR(512)=N'argon2id:S7KBqFYDtoQ/+936WKnRGrfaizX10wKV9mIYdhbsO7M=:ncFDYnCu/jEm22iNzYCxdtkxnIZWWyRHRe7StVKmpvQ=';
DECLARE @RSA INT=(SELECT TOP 1 [Id] FROM [roles] WHERE [Name]=N'SuperAdmin'),@RA INT=(SELECT TOP 1 [Id] FROM [roles] WHERE [Name]=N'Admin'),@RF INT=(SELECT TOP 1 [Id] FROM [roles] WHERE [Name]=N'Faculty'),@RS INT=(SELECT TOP 1 [Id] FROM [roles] WHERE [Name]=N'Student'),@RFn INT=(SELECT TOP 1 [Id] FROM [roles] WHERE [Name]=N'Finance');

/* ── TENANT & CAMPUS ── */
DECLARE @T UNIQUEIDENTIFIER=CAST('A2000000-0000-0000-0000-000000000001' AS UNIQUEIDENTIFIER),@C UNIQUEIDENTIFIER=CAST('B2000000-0000-0000-0000-000000000001' AS UNIQUEIDENTIFIER);
INSERT INTO [tenants] ([Id],[Code],[Name],[IsActive],[IsDeleted],[CreatedAt]) SELECT @T,N'UNI',N'University Tenant',1,0,@Now WHERE NOT EXISTS(SELECT 1 FROM [tenants] WHERE [Code]=N'UNI');
INSERT INTO [campuses] ([Id],[TenantId],[Code],[Name],[IsActive],[IsDeleted],[CreatedAt]) SELECT @C,@T,N'UNI-MAIN',N'University Campus',1,0,@Now WHERE NOT EXISTS(SELECT 1 FROM [campuses] WHERE [Code]=N'UNI-MAIN');

/* ── DEPARTMENTS (4) ── */
DECLARE @CS UNIQUEIDENTIFIER=CAST('C2000000-0000-0000-0000-000000000001' AS UNIQUEIDENTIFIER),@BUS UNIQUEIDENTIFIER=CAST('C2000000-0000-0000-0000-000000000002' AS UNIQUEIDENTIFIER),@ENG UNIQUEIDENTIFIER=CAST('C2000000-0000-0000-0000-000000000003' AS UNIQUEIDENTIFIER),@ART UNIQUEIDENTIFIER=CAST('C2000000-0000-0000-0000-000000000004' AS UNIQUEIDENTIFIER);
INSERT INTO [departments] ([Id],[Name],[Code],[InstitutionType],[TenantId],[CampusId],[IsActive],[IsDeleted],[CreatedAt]) SELECT d.Id,d.Name,d.Code,2,@T,@C,1,0,@Now FROM (VALUES (@CS,N'School of Computer Science',N'CS'),(@BUS,N'School of Business',N'BUS'),(@ENG,N'School of Engineering',N'ENG'),(@ART,N'School of Arts & Humanities',N'ARTS')) d(Id,Name,Code) WHERE NOT EXISTS(SELECT 1 FROM [departments] x WHERE x.[Id]=d.Id OR x.[Code]=d.Code);

/* ── PROGRAMS ── */
INSERT INTO [academic_programs] ([Id],[Name],[Code],[DepartmentId],[TotalSemesters],[MaxCreditLoadPerSemester],[IsActive],[IsDeleted],[CreatedAt]) SELECT p.Id,p.Name,p.Code,p.Did,p.S,p.Cr,1,0,@Now FROM (VALUES (CAST('D2000000-0000-0000-0000-000000000001' AS UNIQUEIDENTIFIER),N'BS Computer Science',N'BSCS',@CS,8,18),(CAST('D2000000-0000-0000-0000-000000000002' AS UNIQUEIDENTIFIER),N'BBA',N'BBA',@BUS,8,18),(CAST('D2000000-0000-0000-0000-000000000003' AS UNIQUEIDENTIFIER),N'BS Electrical Engineering',N'BSEE',@ENG,8,18),(CAST('D2000000-0000-0000-0000-000000000004' AS UNIQUEIDENTIFIER),N'BA English Literature',N'BA-ENG',@ART,4,15)) p(Id,Name,Code,Did,S,Cr) WHERE NOT EXISTS(SELECT 1 FROM [academic_programs] x WHERE x.[Id]=p.Id);

/* ── SEMESTERS (8 = Fall 2025 through Spring 2029) ── */
INSERT INTO [semesters] ([Id],[Name],[StartDate],[EndDate],[IsClosed],[IsDeleted],[CreatedAt]) SELECT s.Id,s.Name,s.StartDate,s.EndDate,s.IsClosed,0,@Now FROM (VALUES (CAST('E2000000-0000-0000-0000-000000000001' AS UNIQUEIDENTIFIER),N'Fall 2025','2025-09-01','2026-01-15',1),(CAST('E2000000-0000-0000-0000-000000000002' AS UNIQUEIDENTIFIER),N'Spring 2026','2026-02-01','2026-06-15',1),(CAST('E2000000-0000-0000-0000-000000000003' AS UNIQUEIDENTIFIER),N'Fall 2026','2026-09-01','2027-01-15',0),(CAST('E2000000-0000-0000-0000-000000000004' AS UNIQUEIDENTIFIER),N'Spring 2027','2027-02-01','2027-06-15',0),(CAST('E2000000-0000-0000-0000-000000000005' AS UNIQUEIDENTIFIER),N'Fall 2027','2027-09-01','2028-01-15',0),(CAST('E2000000-0000-0000-0000-000000000006' AS UNIQUEIDENTIFIER),N'Spring 2028','2028-02-01','2028-06-15',0),(CAST('E2000000-0000-0000-0000-000000000007' AS UNIQUEIDENTIFIER),N'Fall 2028','2028-09-01','2029-01-15',0),(CAST('E2000000-0000-0000-0000-000000000008' AS UNIQUEIDENTIFIER),N'Spring 2029','2029-02-01','2029-06-15',0)) s(Id,Name,StartDate,EndDate,IsClosed) WHERE NOT EXISTS(SELECT 1 FROM [semesters] x WHERE x.[Id]=s.Id);
DECLARE @F25 UNIQUEIDENTIFIER=CAST('E2000000-0000-0000-0000-000000000001' AS UNIQUEIDENTIFIER),@S26 UNIQUEIDENTIFIER=CAST('E2000000-0000-0000-0000-000000000002' AS UNIQUEIDENTIFIER),@F26 UNIQUEIDENTIFIER=CAST('E2000000-0000-0000-0000-000000000003' AS UNIQUEIDENTIFIER),@S27 UNIQUEIDENTIFIER=CAST('E2000000-0000-0000-0000-000000000004' AS UNIQUEIDENTIFIER);

/* ── COURSES (5 per dept = 20) ── */
DECLARE @Cr TABLE (Id UNIQUEIDENTIFIER,T NVARCHAR(200),Cd NVARCHAR(20),CrH INT,Did UNIQUEIDENTIFIER,CT INT,GT NVARCHAR(20));
INSERT INTO @Cr VALUES (CAST('F2000000-0000-0000-0000-000001001' AS UNIQUEIDENTIFIER),N'Programming Fundamentals',N'CS-101',3,@CS,1,N'GPA'),(CAST('F2000000-0000-0000-0000-000001002' AS UNIQUEIDENTIFIER),N'Data Structures',N'CS-201',4,@CS,1,N'GPA'),(CAST('F2000000-0000-0000-0000-000001003' AS UNIQUEIDENTIFIER),N'Database Systems',N'CS-301',4,@CS,1,N'GPA'),(CAST('F2000000-0000-0000-0000-000001004' AS UNIQUEIDENTIFIER),N'Software Engineering',N'CS-401',3,@CS,1,N'GPA'),(CAST('F2000000-0000-0000-0000-000001005' AS UNIQUEIDENTIFIER),N'Artificial Intelligence',N'CS-501',3,@CS,1,N'GPA'),(CAST('F2000000-0000-0000-0000-000002001' AS UNIQUEIDENTIFIER),N'Principles of Management',N'BUS-101',3,@BUS,1,N'GPA'),(CAST('F2000000-0000-0000-0000-000002002' AS UNIQUEIDENTIFIER),N'Financial Accounting',N'BUS-201',4,@BUS,1,N'GPA'),(CAST('F2000000-0000-0000-0000-000002003' AS UNIQUEIDENTIFIER),N'Marketing Management',N'BUS-301',3,@BUS,1,N'GPA'),(CAST('F2000000-0000-0000-0000-000002004' AS UNIQUEIDENTIFIER),N'Organizational Behavior',N'BUS-401',3,@BUS,1,N'GPA'),(CAST('F2000000-0000-0000-0000-000002005' AS UNIQUEIDENTIFIER),N'Business Analytics',N'BUS-501',3,@BUS,1,N'GPA'),(CAST('F2000000-0000-0000-0000-000003001' AS UNIQUEIDENTIFIER),N'Circuit Analysis',N'ENG-101',4,@ENG,1,N'GPA'),(CAST('F2000000-0000-0000-0000-000003002' AS UNIQUEIDENTIFIER),N'Digital Logic Design',N'ENG-201',4,@ENG,1,N'GPA'),(CAST('F2000000-0000-0000-0000-000003003' AS UNIQUEIDENTIFIER),N'Signals & Systems',N'ENG-301',3,@ENG,1,N'GPA'),(CAST('F2000000-0000-0000-0000-000003004' AS UNIQUEIDENTIFIER),N'Microprocessors',N'ENG-401',4,@ENG,1,N'GPA'),(CAST('F2000000-0000-0000-0000-000003005' AS UNIQUEIDENTIFIER),N'Power Systems',N'ENG-501',3,@ENG,1,N'GPA'),(CAST('F2000000-0000-0000-0000-000004001' AS UNIQUEIDENTIFIER),N'English Literature I',N'ARTS-101',3,@ART,1,N'GPA'),(CAST('F2000000-0000-0000-0000-000004002' AS UNIQUEIDENTIFIER),N'Creative Writing',N'ARTS-201',3,@ART,2,N'GPA'),(CAST('F2000000-0000-0000-0000-000004003' AS UNIQUEIDENTIFIER),N'Linguistics',N'ARTS-301',3,@ART,1,N'GPA'),(CAST('F2000000-0000-0000-0000-000004004' AS UNIQUEIDENTIFIER),N'Philosophy',N'ARTS-401',3,@ART,2,N'GPA'),(CAST('F2000000-0000-0000-0000-000004005' AS UNIQUEIDENTIFIER),N'World History',N'ARTS-501',3,@ART,2,N'GPA');
INSERT INTO [courses] ([Id],[Title],[Code],[CreditHours],[DepartmentId],[CourseType],[GradingType],[HasSemesters],[IsActive],[IsDeleted],[CreatedAt]) SELECT c.Id,c.T,c.Cd,c.CrH,c.Did,c.CT,c.GT,1,1,0,@Now FROM @Cr c WHERE NOT EXISTS(SELECT 1 FROM [courses] x WHERE x.[Id]=c.Id);

/* ── USERS ── */
DECLARE @SA UNIQUEIDENTIFIER=CAST('70000000-0000-0000-0000-000000000001' AS UNIQUEIDENTIFIER),@ACs UNIQUEIDENTIFIER=CAST('70000A00-0000-0000-0000-000000000001' AS UNIQUEIDENTIFIER),@ABu UNIQUEIDENTIFIER=CAST('70000A00-0000-0000-0000-000000000002' AS UNIQUEIDENTIFIER),@AEn UNIQUEIDENTIFIER=CAST('70000A00-0000-0000-0000-000000000003' AS UNIQUEIDENTIFIER),@AAr UNIQUEIDENTIFIER=CAST('70000A00-0000-0000-0000-000000000004' AS UNIQUEIDENTIFIER),@FN UNIQUEIDENTIFIER=CAST('70000A00-0000-0000-0000-000000000005' AS UNIQUEIDENTIFIER);
